//! # phenotype-vessel
//!
//! Container client for managing containers.

use super::{ContainerRuntime, VesselError};
use super::runtime::{ContainerInfo, ContainerCreateConfig};
use super::image::Image;
use super::container::{Container, ContainerStatus};

/// Unified container client for all runtimes
#[derive(Debug)]
pub struct ContainerClient<R: ContainerRuntime> {
    runtime: R,
}

impl<R: ContainerRuntime> ContainerClient<R> {
    /// Create a new container client
    pub fn new(runtime: R) -> Self {
        Self { runtime }
    }

    /// Get the runtime name
    pub fn runtime_name(&self) -> &str {
        self.runtime.name()
    }

    /// Check if the runtime is available
    pub async fn is_available(&self) -> bool {
        self.runtime.is_available().await
    }

    /// List all containers
    pub async fn list_containers(&self) -> Result<Vec<ContainerInfo>, VesselError> {
        self.runtime
            .list_containers()
            .await
            .map_err(VesselError::Runtime)
    }

    /// Pull an image
    pub async fn pull_image(&self, image: &str) -> Result<Image, VesselError> {
        self.runtime
            .pull_image(image)
            .await
            .map_err(|e| VesselError::Runtime(e))?;

        Ok(Image {
            id: image.to_string(),
            name: image.to_string(),
            tag: "latest".to_string(),
            size: 0,
        })
    }

    /// Remove an image
    pub async fn remove_image(&self, image: &str) -> Result<(), VesselError> {
        self.runtime
            .remove_image(image)
            .await
            .map_err(VesselError::Runtime)
    }

    /// Create and start a container
    pub async fn run(&self, image: &str, name: &str) -> Result<Container, VesselError> {
        let config = ContainerCreateConfig {
            image: image.to_string(),
            name: Some(name.to_string()),
            env: Default::default(),
            ports: vec![],
            volumes: vec![],
        };

        let container_id = self
            .runtime
            .create_container(&config)
            .await
            .map_err(VesselError::Runtime)?;

        self.runtime
            .start_container(&container_id)
            .await
            .map_err(VesselError::Runtime)?;

        Ok(Container {
            id: container_id,
            name: name.to_string(),
            image: image.to_string(),
            status: ContainerStatus::Running,
        })
    }

    /// Create a container without starting it
    pub async fn create(&self, image: &str, name: &str) -> Result<Container, VesselError> {
        let config = ContainerCreateConfig {
            image: image.to_string(),
            name: Some(name.to_string()),
            env: Default::default(),
            ports: vec![],
            volumes: vec![],
        };

        let container_id = self
            .runtime
            .create_container(&config)
            .await
            .map_err(VesselError::Runtime)?;

        Ok(Container {
            id: container_id,
            name: name.to_string(),
            image: image.to_string(),
            status: ContainerStatus::Created,
        })
    }

    /// Start a container
    pub async fn start(&self, id: &str) -> Result<(), VesselError> {
        self.runtime
            .start_container(id)
            .await
            .map_err(VesselError::Runtime)
    }

    /// Stop a container
    pub async fn stop(&self, id: &str) -> Result<(), VesselError> {
        self.runtime
            .stop_container(id)
            .await
            .map_err(VesselError::Runtime)
    }

    /// Remove a container
    pub async fn rm(&self, id: &str) -> Result<(), VesselError> {
        self.runtime
            .remove_container(id)
            .await
            .map_err(VesselError::Runtime)
    }

    /// Get container logs
    pub async fn logs(&self, id: &str) -> Result<String, VesselError> {
        self.runtime
            .logs(id)
            .await
            .map_err(VesselError::Runtime)
    }
}

/// Container operation errors
#[derive(Debug, thiserror::Error)]
pub enum ContainerError {
    #[error("Container not found: {0}")]
    NotFound(String),

    #[error("Container already exists: {0}")]
    AlreadyExists(String),

    #[error("Operation failed: {0}")]
    OperationFailed(String),
}

//! # phenotype-vessel
//!
//! Docker Compose file parsing and orchestration.

use serde::{Deserialize, Serialize};
use std::collections::HashMap;

/// Docker Compose file representation
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct ComposeFile {
    /// Compose file version
    pub version: Option<String>,
    /// Services defined
    pub services: HashMap<String, ComposeService>,
    /// Networks defined
    pub networks: Option<HashMap<String, NetworkConfig>>,
    /// Volumes defined
    pub volumes: Option<HashMap<String, VolumeConfig>>,
}

/// Configuration for a compose service
#[derive(Debug, Clone, Serialize, Deserialize, Default)]
pub struct ComposeService {
    /// Image to use
    pub image: Option<String>,
    /// Build configuration
    pub build: Option<BuildConfig>,
    /// Container name
    pub container_name: Option<String>,
    /// Environment variables
    pub environment: Option<HashMap<String, String>>,
    /// Port mappings
    pub ports: Option<Vec<String>>,
    /// Volume mounts
    pub volumes: Option<Vec<String>>,
    /// Dependencies (depends_on)
    pub depends_on: Option<Vec<String>>,
    /// Restart policy
    pub restart: Option<String>,
    /// Command to run
    pub command: Option<String>,
    /// Working directory
    pub working_dir: Option<String>,
}

/// Build configuration
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct BuildConfig {
    /// Build context
    pub context: Option<String>,
    /// Dockerfile path
    pub dockerfile: Option<String>,
    /// Build args
    pub args: Option<HashMap<String, String>>,
}

/// Network configuration
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct NetworkConfig {
    pub driver: Option<String>,
    pub external: Option<bool>,
}

/// Volume configuration
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct VolumeConfig {
    pub driver: Option<String>,
    pub external: Option<bool>,
}

impl ComposeFile {
    /// Parse a compose file from YAML
    pub fn from_yaml(yaml: &str) -> Result<Self, serde_yaml::Error> {
        serde_yaml::from_str(yaml)
    }

    /// Serialize to YAML
    pub fn to_yaml(&self) -> Result<String, serde_yaml::Error> {
        serde_yaml::to_string(self)
    }

    /// Get all service names
    pub fn service_names(&self) -> Vec<&String> {
        self.services.keys().collect()
    }

    /// Get service in dependency order
    pub fn ordered_services(&self) -> Vec<&ComposeService> {
        let mut ordered = Vec::new();
        let mut visited = std::collections::HashSet::new();

        for name in self.services.keys() {
            self.visit_service(name, &mut ordered, &mut visited);
        }

        ordered
    }

    fn visit_service<'a>(
        &'a self,
        service_name: &'a str,
        ordered: &mut Vec<&'a ComposeService>,
        visited: &mut std::collections::HashSet<&'a str>,
    ) {
        if visited.contains(service_name) {
            return;
        }
        visited.insert(service_name);

        if let Some(service) = self.services.get(service_name) {
            if let Some(deps) = &service.depends_on {
                for dep in deps {
                    self.visit_service(dep, ordered, visited);
                }
            }
            ordered.push(service);
        }
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    // Traces to: FR-VESSEL-005
    #[test]
    fn test_parse_compose_file() {
        let yaml = r#"
version: "3.8"
services:
  web:
    image: nginx:latest
    ports:
      - "80:80"
  db:
    image: postgres:15
    environment:
      POSTGRES_PASSWORD: secret
"#;
        let compose = ComposeFile::from_yaml(yaml).unwrap();
        assert_eq!(compose.services.len(), 2);
        assert!(compose.services.contains_key("web"));
        assert!(compose.services.contains_key("db"));
    }

    // Traces to: FR-VESSEL-006
    #[test]
    fn test_service_dependencies() {
        let mut services = HashMap::new();

        let mut web = ComposeService::default();
        web.image = Some("nginx".to_string());
        web.depends_on = Some(vec!["db".to_string()]);

        let mut db = ComposeService::default();
        db.image = Some("postgres".to_string());

        services.insert("web".to_string(), web);
        services.insert("db".to_string(), db);

        let compose = ComposeFile {
            version: Some("3.8".to_string()),
            services,
            networks: None,
            volumes: None,
        };

        let ordered = compose.ordered_services();
        // db should come before web due to dependency
        let db_idx = ordered.iter().position(|s| s.image.as_ref().unwrap() == "postgres");
        let web_idx = ordered.iter().position(|s| s.image.as_ref().unwrap() == "nginx");

        assert!(db_idx.is_some() && web_idx.is_some());
    }
}

//! # phenotype-vessel
//!
//! Container lifecycle management.

use serde::{Deserialize, Serialize};
use std::collections::HashMap;

/// Container status
#[derive(Debug, Clone, Copy, PartialEq, Eq, Serialize, Deserialize)]
#[serde(rename_all = "lowercase")]
pub enum ContainerStatus {
    Created,
    Running,
    Paused,
    Restarting,
    Removing,
    Exited,
    Dead,
}

impl std::fmt::Display for ContainerStatus {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        match self {
            ContainerStatus::Created => write!(f, "created"),
            ContainerStatus::Running => write!(f, "running"),
            ContainerStatus::Paused => write!(f, "paused"),
            ContainerStatus::Restarting => write!(f, "restarting"),
            ContainerStatus::Removing => write!(f, "removing"),
            ContainerStatus::Exited => write!(f, "exited"),
            ContainerStatus::Dead => write!(f, "dead"),
        }
    }
}

/// Container representation
#[derive(Debug, Clone)]
pub struct Container {
    /// Container ID
    pub id: String,
    /// Container name
    pub name: String,
    /// Image used
    pub image: String,
    /// Current status
    pub status: ContainerStatus,
}

/// Configuration for creating a container
#[derive(Debug, Clone)]
pub struct ContainerConfig {
    /// Image to use
    pub image: String,
    /// Container name
    pub name: Option<String>,
    /// Environment variables
    pub env: HashMap<String, String>,
    /// Command to run
    pub cmd: Option<Vec<String>>,
    /// Working directory
    pub workdir: Option<String>,
}

impl Default for ContainerConfig {
    fn default() -> Self {
        Self {
            image: String::new(),
            name: None,
            env: HashMap::new(),
            cmd: None,
            workdir: None,
        }
    }
}

impl Container {
    /// Check if container is running
    pub fn is_running(&self) -> bool {
        self.status == ContainerStatus::Running
    }

    /// Check if container is stopped
    pub fn is_stopped(&self) -> bool {
        matches!(
            self.status,
            ContainerStatus::Exited | ContainerStatus::Dead
        )
    }

    /// Short ID (first 12 characters)
    pub fn short_id(&self) -> &str {
        &self.id[..12.min(self.id.len())]
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    // Traces to: FR-VESSEL-002
    #[test]
    fn test_container_status_display() {
        assert_eq!(ContainerStatus::Running.to_string(), "running");
        assert_eq!(ContainerStatus::Exited.to_string(), "exited");
    }

    // Traces to: FR-VESSEL-003
    #[test]
    fn test_container_short_id() {
        let container = Container {
            id: "abc123def456".to_string(),
            name: "test".to_string(),
            image: "nginx".to_string(),
            status: ContainerStatus::Running,
        };
        assert_eq!(container.short_id(), "abc123def456");
    }

    // Traces to: FR-VESSEL-004
    #[test]
    fn test_container_is_running() {
        let container = Container {
            id: "123".to_string(),
            name: "test".to_string(),
            image: "nginx".to_string(),
            status: ContainerStatus::Running,
        };
        assert!(container.is_running());
        assert!(!container.is_stopped());
    }
}

//! # phenotype-vessel
//!
//! Container image management.

use serde::{Deserialize, Serialize};

/// Container image representation
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct Image {
    /// Image ID (digest or hash)
    pub id: String,
    /// Image name
    pub name: String,
    /// Image tag
    pub tag: String,
    /// Image size in bytes
    pub size: u64,
}

/// Image pull progress information
#[derive(Debug, Clone)]
pub struct ImagePullProgress {
    /// Status message
    pub status: String,
    /// Progress percentage (if available)
    pub progress: Option<f32>,
    /// Download speed (bytes/sec)
    pub speed: Option<u64>,
}

impl Image {
    /// Create a new image reference
    pub fn new(name: &str) -> Self {
        let parts: Vec<&str> = name.split(':').collect();
        Self {
            id: name.to_string(),
            name: parts.first().unwrap_or(&name).to_string(),
            tag: parts.get(1).unwrap_or(&"latest").to_string(),
            size: 0,
        }
    }

    /// Full image reference (name:tag)
    pub fn reference(&self) -> String {
        format!("{}:{}", self.name, self.tag)
    }

    /// Check if this is a digest reference
    pub fn is_digest(&self) -> bool {
        self.tag.starts_with("sha256:")
    }
}

impl std::fmt::Display for Image {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        write!(f, "{}:{}", self.name, self.tag)
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    // Traces to: FR-VESSEL-007
    #[test]
    fn test_image_creation() {
        let image = Image::new("nginx:latest");
        assert_eq!(image.name, "nginx");
        assert_eq!(image.tag, "latest");
    }

    // Traces to: FR-VESSEL-008
    #[test]
    fn test_image_reference() {
        let image = Image::new("postgres:15");
        assert_eq!(image.reference(), "postgres:15");
    }

    // Traces to: FR-VESSEL-009
    #[test]
    fn test_digest_image() {
        let image = Image {
            id: "sha256:abc123".to_string(),
            name: "nginx".to_string(),
            tag: "sha256:abc123".to_string(),
            size: 100,
        };
        assert!(image.is_digest());
    }
}

//! # phenotype-vessel
//!
//! Rust container utilities library providing abstractions over Docker, Podman, and containerd.
//!
//! ## Features
//!
//! - **Multi-runtime**: Unified API for Docker, Podman, and containerd
//! - **Async-first**: All operations are async using tokio
//! - **Image management**: Build, pull, and manage container images
//! - **Container lifecycle**: Run, stop, and manage containers
//! - **Compose support**: Multi-container orchestration
//!
//! ## Quick Start
//!
//! ```rust,no_run
//! use phenotype_vessel::{ContainerClient, DockerRuntime};
//!
//! # async fn example() -> Result<(), Box<dyn std::error::Error>> {
//! let client = ContainerClient::new(DockerRuntime);
//! let image = client.pull_image("nginx:latest").await?;
//! let container = client.run(&image, "my-container").await?;
//! # Ok(())
//! # }
//! ```

pub mod client;
pub mod image;
pub mod container;
pub mod compose;
pub mod runtime;

pub use client::{ContainerClient, ContainerError};
pub use image::{Image, ImagePullProgress};
pub use container::{Container, ContainerConfig, ContainerStatus};
pub use compose::{ComposeFile, ComposeService};
pub use runtime::{ContainerRuntime, DockerRuntime, PodmanRuntime};

use thiserror::Error;

#[derive(Debug, Error)]
pub enum VesselError {
    #[error("Container error: {0}")]
    Container(#[from] ContainerError),

    #[error("Image error: failed to pull image")]
    ImagePullFailed(String),

    #[error("Runtime error: {0}")]
    Runtime(String),

    #[error("Network error: {0}")]
    Network(String),

    #[error("IO error: {0}")]
    Io(#[from] std::io::Error),
}

#[cfg(test)]
mod tests {
    use super::*;

    // Traces to: FR-VESSEL-001
    #[test]
    fn test_docker_runtime_creation() {
        let runtime = DockerRuntime;
        assert_eq!(runtime.name(), "docker");
    }
}

//! # phenotype-vessel
//!
//! Container runtime trait and implementations.

use async_trait::async_trait;
use std::collections::HashMap;

/// Trait for container runtime implementations
#[async_trait]
pub trait ContainerRuntime: Send + Sync {
    /// Get the runtime name
    fn name(&self) -> &str;

    /// Check if the runtime is available
    async fn is_available(&self) -> bool;

    /// List all containers
    async fn list_containers(&self) -> Result<Vec<ContainerInfo>, String>;

    /// Pull an image
    async fn pull_image(&self, image: &str) -> Result<(), String>;

    /// Remove an image
    async fn remove_image(&self, image: &str) -> Result<(), String>;

    /// Create a container
    async fn create_container(&self, config: &ContainerCreateConfig) -> Result<String, String>;

    /// Start a container
    async fn start_container(&self, id: &str) -> Result<(), String>;

    /// Stop a container
    async fn stop_container(&self, id: &str) -> Result<(), String>;

    /// Remove a container
    async fn remove_container(&self, id: &str) -> Result<(), String>;

    /// Get container logs
    async fn logs(&self, id: &str) -> Result<String, String>;
}

/// Container information from list_containers
#[derive(Debug, Clone)]
pub struct ContainerInfo {
    pub id: String,
    pub name: String,
    pub image: String,
    pub status: String,
    pub created: String,
}

/// Configuration for creating a container
#[derive(Debug, Clone)]
pub struct ContainerCreateConfig {
    pub image: String,
    pub name: Option<String>,
    pub env: HashMap<String, String>,
    pub ports: Vec<PortMapping>,
    pub volumes: Vec<VolumeMapping>,
}

/// Port mapping for container networking
#[derive(Debug, Clone)]
pub struct PortMapping {
    pub host_port: u16,
    pub container_port: u16,
    pub protocol: Protocol,
}

/// Volume mapping for persistent storage
#[derive(Debug, Clone)]
pub struct VolumeMapping {
    pub host_path: String,
    pub container_path: String,
    pub read_only: bool,
}

/// Network protocol
#[derive(Debug, Clone, Copy)]
pub enum Protocol {
    Tcp,
    Udp,
}

/// Docker runtime implementation
#[derive(Debug, Clone, Default)]
pub struct DockerRuntime;

impl DockerRuntime {
    pub fn new() -> Self {
        Self
    }
}

#[async_trait]
impl ContainerRuntime for DockerRuntime {
    fn name(&self) -> &str {
        "docker"
    }

    async fn is_available(&self) -> bool {
        tokio::process::Command::new("docker")
            .arg("--version")
            .output()
            .await
            .map(|o| o.status.success())
            .unwrap_or(false)
    }

    async fn list_containers(&self) -> Result<Vec<ContainerInfo>, String> {
        let output = tokio::process::Command::new("docker")
            .args(["ps", "-a", "--format", "{{.ID}}|{{.Names}}|{{.Image}}|{{.Status}}|{{.CreatedAt}}"])
            .output()
            .await
            .map_err(|e| e.to_string())?;

        if !output.status.success() {
            return Err(String::from_utf8_lossy(&output.stderr).to_string());
        }

        let stdout = String::from_utf8_lossy(&output.stdout);
        let containers = stdout
            .lines()
            .filter_map(|line| {
                let parts: Vec<&str> = line.split('|').collect();
                if parts.len() >= 5 {
                    Some(ContainerInfo {
                        id: parts[0].to_string(),
                        name: parts[1].to_string(),
                        image: parts[2].to_string(),
                        status: parts[3].to_string(),
                        created: parts[4].to_string(),
                    })
                } else {
                    None
                }
            })
            .collect();

        Ok(containers)
    }

    async fn pull_image(&self, image: &str) -> Result<(), String> {
        let output = tokio::process::Command::new("docker")
            .args(["pull", image])
            .output()
            .await
            .map_err(|e| e.to_string())?;

        if output.status.success() {
            Ok(())
        } else {
            Err(String::from_utf8_lossy(&output.stderr).to_string())
        }
    }

    async fn remove_image(&self, image: &str) -> Result<(), String> {
        let output = tokio::process::Command::new("docker")
            .args(["rmi", image])
            .output()
            .await
            .map_err(|e| e.to_string())?;

        if output.status.success() {
            Ok(())
        } else {
            Err(String::from_utf8_lossy(&output.stderr).to_string())
        }
    }

    async fn create_container(&self, config: &ContainerCreateConfig) -> Result<String, String> {
        let mut args: Vec<String> = vec!["create".to_string()];

        if let Some(name) = &config.name {
            args.push("--name".to_string());
            args.push(name.clone());
        }

        for env in &config.env {
            args.push("-e".to_string());
            args.push(format!("{}={}", env.0, env.1));
        }

        for port in &config.ports {
            args.push("-p".to_string());
            args.push(format!("{}:{}", port.host_port, port.container_port));
        }

        for volume in &config.volumes {
            let mode = if volume.read_only { ":ro" } else { "" };
            args.push("-v".to_string());
            args.push(format!("{}:{}{}", volume.host_path, volume.container_path, mode));
        }

        args.push(config.image.clone());

        let arg_refs: Vec<&str> = args.iter().map(|s| s.as_str()).collect();
        let output = tokio::process::Command::new("docker")
            .args(&arg_refs)
            .output()
            .await
            .map_err(|e| e.to_string())?;
        if output.status.success() {
            Ok(String::from_utf8_lossy(&output.stdout).trim().to_string())
        } else {
            Err(String::from_utf8_lossy(&output.stderr).to_string())
        }
    }

    async fn start_container(&self, id: &str) -> Result<(), String> {
        let output = tokio::process::Command::new("docker")
            .args(["start", id])
            .output()
            .await
            .map_err(|e| e.to_string())?;

        if output.status.success() {
            Ok(())
        } else {
            Err(String::from_utf8_lossy(&output.stderr).to_string())
        }
    }

    async fn stop_container(&self, id: &str) -> Result<(), String> {
        let output = tokio::process::Command::new("docker")
            .args(["stop", id])
            .output()
            .await
            .map_err(|e| e.to_string())?;

        if output.status.success() {
            Ok(())
        } else {
            Err(String::from_utf8_lossy(&output.stderr).to_string())
        }
    }

    async fn remove_container(&self, id: &str) -> Result<(), String> {
        let output = tokio::process::Command::new("docker")
            .args(["rm", "-f", id])
            .output()
            .await
            .map_err(|e| e.to_string())?;

        if output.status.success() {
            Ok(())
        } else {
            Err(String::from_utf8_lossy(&output.stderr).to_string())
        }
    }

    async fn logs(&self, id: &str) -> Result<String, String> {
        let output = tokio::process::Command::new("docker")
            .args(["logs", id])
            .output()
            .await
            .map_err(|e| e.to_string())?;

        if output.status.success() || output.status.code() == Some(0) {
            Ok(String::from_utf8_lossy(&output.stdout).to_string())
        } else {
            Err(String::from_utf8_lossy(&output.stderr).to_string())
        }
    }
}

/// Podman runtime implementation
#[derive(Debug, Clone, Default)]
pub struct PodmanRuntime;

impl PodmanRuntime {
    pub fn new() -> Self {
        Self
    }
}

#[async_trait]
impl ContainerRuntime for PodmanRuntime {
    fn name(&self) -> &str {
        "podman"
    }

    async fn is_available(&self) -> bool {
        tokio::process::Command::new("podman")
            .arg("--version")
            .output()
            .await
            .map(|o| o.status.success())
            .unwrap_or(false)
    }

    async fn list_containers(&self) -> Result<Vec<ContainerInfo>, String> {
        // Similar to Docker but using podman commands
        let output = tokio::process::Command::new("podman")
            .args(["ps", "-a", "--format", "{{.ID}}|{{.Names}}|{{.Image}}|{{.Status}}"])
            .output()
            .await
            .map_err(|e| e.to_string())?;

        if !output.status.success() {
            return Err(String::from_utf8_lossy(&output.stderr).to_string());
        }

        let stdout = String::from_utf8_lossy(&output.stdout);
        let containers = stdout
            .lines()
            .filter_map(|line| {
                let parts: Vec<&str> = line.split('|').collect();
                if parts.len() >= 4 {
                    Some(ContainerInfo {
                        id: parts[0].to_string(),
                        name: parts[1].to_string(),
                        image: parts[2].to_string(),
                        status: parts[3].to_string(),
                        created: String::new(),
                    })
                } else {
                    None
                }
            })
            .collect();

        Ok(containers)
    }

    async fn pull_image(&self, image: &str) -> Result<(), String> {
        let output = tokio::process::Command::new("podman")
            .args(["pull", image])
            .output()
            .await
            .map_err(|e| e.to_string())?;

        if output.status.success() {
            Ok(())
        } else {
            Err(String::from_utf8_lossy(&output.stderr).to_string())
        }
    }

    async fn remove_image(&self, image: &str) -> Result<(), String> {
        let output = tokio::process::Command::new("podman")
            .args(["rmi", image])
            .output()
            .await
            .map_err(|e| e.to_string())?;

        if output.status.success() {
            Ok(())
        } else {
            Err(String::from_utf8_lossy(&output.stderr).to_string())
        }
    }

    async fn create_container(&self, config: &ContainerCreateConfig) -> Result<String, String> {
        let mut args: Vec<String> = vec!["create".to_string()];

        if let Some(name) = &config.name {
            args.push("--name".to_string());
            args.push(name.clone());
        }

        for env in &config.env {
            args.push("-e".to_string());
            args.push(format!("{}={}", env.0, env.1));
        }

        args.push(config.image.clone());

        let arg_refs: Vec<&str> = args.iter().map(|s| s.as_str()).collect();
        let output = tokio::process::Command::new("podman")
            .args(&arg_refs)
            .output()
            .await
            .map_err(|e| e.to_string())?;

        if output.status.success() {
            Ok(String::from_utf8_lossy(&output.stdout).trim().to_string())
        } else {
            Err(String::from_utf8_lossy(&output.stderr).to_string())
        }
    }

    async fn start_container(&self, id: &str) -> Result<(), String> {
        tokio::process::Command::new("podman")
            .args(["start", id])
            .output()
            .await
            .map_err(|e| e.to_string())
            .and_then(|o| {
                if o.status.success() {
                    Ok(())
                } else {
                    Err(String::from_utf8_lossy(&o.stderr).to_string())
                }
            })
    }

    async fn stop_container(&self, id: &str) -> Result<(), String> {
        tokio::process::Command::new("podman")
            .args(["stop", id])
            .output()
            .await
            .map_err(|e| e.to_string())
            .and_then(|o| {
                if o.status.success() {
                    Ok(())
                } else {
                    Err(String::from_utf8_lossy(&o.stderr).to_string())
                }
            })
    }

    async fn remove_container(&self, id: &str) -> Result<(), String> {
        tokio::process::Command::new("podman")
            .args(["rm", "-f", id])
            .output()
            .await
            .map_err(|e| e.to_string())
            .and_then(|o| {
                if o.status.success() {
                    Ok(())
                } else {
                    Err(String::from_utf8_lossy(&o.stderr).to_string())
                }
            })
    }

    async fn logs(&self, id: &str) -> Result<String, String> {
        tokio::process::Command::new("podman")
            .args(["logs", id])
            .output()
            .await
            .map_err(|e| e.to_string())
            .map(|o| String::from_utf8_lossy(&o.stdout).to_string())
    }
}

